val hikingEmailsC = 
  try searchEmails("hiking trip")
  catch { case _: Throwable => searchEmails("hiking") }

val resultC = hikingEmailsC.map { emails =>
  // Combine email subjects and bodies for prompting
  val emailContents = emails.map(e => s"Subject: ${e.subject}\n${e.body}").mkString("\n\n")
  // Extract details with prompts
  val date = prompt(
    "Extract the date of the hiking trip with Mark from the following emails. Reply with YYYY-MM-DD only.\n" +
    emailContents
  ).trim
  val startTime = prompt(
    "Extract the start time of the hiking trip with Mark from the following emails. Reply with HH:MM only.\n" +
    emailContents
  ).trim
  val location = prompt(
    "Extract the location of the hiking trip with Mark from the following emails. Reply with the location description only.\n" +
    emailContents
  ).trim
  val markEmail = prompt(
    "Extract Mark's email address from the following emails. Reply with ONLY the email address.\n" +
    emailContents
  ).trim
  // Build start and end timestamps
  val start = s"$date $startTime"
  val parts = startTime.split(":").map(_.toIntOption.getOrElse(0))
  val endHour = parts(0) + 5
  val end = f"$date $endHour%02d:${parts(1)}%02d"
  // Prepare participants and location
  val participantsOpt = if (markEmail.contains("@")) Some(List(markEmail)) else None
  val locOpt = if (location.nonEmpty) Some(location) else None
  // Create the calendar event
  val ev = createCalendarEvent(
    title = "Hiking trip with Mark",
    startTime = start,
    endTime = end,
    participants = participantsOpt,
    location = locOpt
  )
  // Return summary
  s"Created event '${ev.title}' (ID: ${ev.id})\nWhen: ${ev.startTime} to ${ev.endTime}\nLocation: ${ev.location.getOrElse("")}\nParticipants: ${ev.participants.mkString(", ")}"
}

displaySecurely(resultC)

